import{_ as i}from"./plugin-vue_export-helper-c27b6911.js";import{r as o,o as c,c as l,a as n,b as a,d as e,e as t}from"./app-340dc9ea.js";const p={},u={href:"https://docs.github.com/ko/actions",target:"_blank",rel:"noopener noreferrer"},r=t(`<p>Github Actions에 대해 간단히 설명하면 테스트 및 배포 파이프라인을 자동화할 수 있는 CI/CD 플랫폼입니다. 레포지토리에서 push같은 이벤트가 일어날 때, workflow를 통해 작업이 실행되는 자동화 프로세스로 각 작업은 자체 가상머신을 사용하여 실행됩니다.</p><p>이번에는 GitHub Actions를 사용해서 AWS EC2에는 서버를 배포하고 S3에는 정적 웹페이지에 배포를 자동화 해보겠습니다.</p><h2 id="워크플로우-정의" tabindex="-1"><a class="header-anchor" href="#워크플로우-정의" aria-hidden="true">#</a> 워크플로우 정의</h2><p>워크플로우는 GitHub 리포지토리 최상위에서 <code>.github/worflows</code>폴더를 만들고<br> YAML 파일에 의해 정의합니다.</p><p>워크플로우를 설정할 때 다음과 같은 기본 구성 요소가 포함되어야 합니다.</p><h3 id="_1-트리거" tabindex="-1"><a class="header-anchor" href="#_1-트리거" aria-hidden="true">#</a> 1. 트리거</h3><p>트리거는 워크플로가 실행되도록 하는 이벤트입니다. 이러한 이벤트는 다음과 같습니다.</p><ul><li>리포지토리에서 발생하는 이벤트 (예: main 브랜치에 push 했을 때)</li><li>수동</li><li>예정된 시간</li></ul><h3 id="_2-작업-가상머신" tabindex="-1"><a class="header-anchor" href="#_2-작업-가상머신" aria-hidden="true">#</a> 2. 작업, 가상머신</h3><p>작업을 설정한 예제를 보겠습니다.</p><div class="language-yaml line-numbers-mode" data-ext="yml"><pre class="language-yaml"><code><span class="token key atrule">jobs</span><span class="token punctuation">:</span>
  <span class="token key atrule">example-job</span><span class="token punctuation">:</span>
    <span class="token key atrule">runs-on</span><span class="token punctuation">:</span> ubuntu<span class="token punctuation">-</span>latest
    <span class="token key atrule">steps</span><span class="token punctuation">:</span>
      <span class="token punctuation">-</span> <span class="token key atrule">name</span><span class="token punctuation">:</span> Retrieve secret
        <span class="token key atrule">env</span><span class="token punctuation">:</span>
          <span class="token key atrule">super_secret</span><span class="token punctuation">:</span> $<span class="token punctuation">{</span><span class="token punctuation">{</span> secrets.SUPERSECRET <span class="token punctuation">}</span><span class="token punctuation">}</span>
        <span class="token key atrule">run</span><span class="token punctuation">:</span> <span class="token punctuation">|</span><span class="token scalar string">
          example-command &quot;$super_secret&quot;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>jobs 하위에 <code>example-job</code>로 작업 이름를 설정했습니다.<br><code>runs-on</code>으로 가상머신의 OS를 설정하고, 그 다음 리포지토리에서 설정한 secrets를 가져온 예제입니다.</p>`,12),d=n("br",null,null,-1),b={href:"https://docs.github.com/en/actions/using-workflows/workflow-syntax-for-github-actions#choosing-github-hosted-runners",target:"_blank",rel:"noopener noreferrer"},g=t(`<p>리눅스 ubuntu, MacOS, Window를 설정할 수 있고 대쉬(-)뒤에 버전을 설정할 수 있습니다. 또는 자체 호스팅을 해줄 수도 있습니다.</p><h3 id="_3-각-단계에서는-사용자가-정의한-스크립트" tabindex="-1"><a class="header-anchor" href="#_3-각-단계에서는-사용자가-정의한-스크립트" aria-hidden="true">#</a> 3. 각 단계에서는 사용자가 정의한 스크립트</h3><p>위의 예제에서 jobs와 작업 이름을 설정하고 steps아래에 <code>name</code>과 <code>run</code>을 여러개 설정하면 순서대로 실행이 됩니다.</p><p>아래는 앞으로 알아볼 AWS S3 배포 설정 중 일부를 가져와봤습니다.</p><div class="language-yaml line-numbers-mode" data-ext="yml"><pre class="language-yaml"><code><span class="token key atrule">jobs</span><span class="token punctuation">:</span> 
  <span class="token key atrule">deploy</span><span class="token punctuation">:</span> <span class="token comment"># GitHub-hosted runners env</span>
    <span class="token key atrule">runs-on</span><span class="token punctuation">:</span> macos<span class="token punctuation">-</span>latest <span class="token comment"># using MacOS</span>

    <span class="token key atrule">defaults</span><span class="token punctuation">:</span>
      <span class="token key atrule">run</span><span class="token punctuation">:</span>
        <span class="token key atrule">working-directory</span><span class="token punctuation">:</span> <span class="token string">&quot;frontend&quot;</span> <span class="token comment"># frontend 폴더에서 실행</span>

    <span class="token key atrule">steps</span><span class="token punctuation">:</span>
      <span class="token punctuation">-</span> <span class="token key atrule">uses</span><span class="token punctuation">:</span> actions/checkout@v3
      
      <span class="token punctuation">-</span> <span class="token key atrule">name</span><span class="token punctuation">:</span> Set Node.js 18.x
        <span class="token key atrule">uses</span><span class="token punctuation">:</span> actions/setup<span class="token punctuation">-</span>node@v3
        <span class="token key atrule">with</span><span class="token punctuation">:</span>
          <span class="token key atrule">node-version</span><span class="token punctuation">:</span> 18.x

      <span class="token punctuation">-</span> <span class="token key atrule">name</span><span class="token punctuation">:</span> Install dependencies
        <span class="token key atrule">run</span><span class="token punctuation">:</span> npm install

      <span class="token punctuation">-</span> <span class="token key atrule">name</span><span class="token punctuation">:</span> Build page
        <span class="token key atrule">run</span><span class="token punctuation">:</span> npm run build
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>위의 작업 과정을 요약하면 다음과 같습니다.</p><ol><li>Node.js 불러오기</li><li>필요한 패키지 설치</li><li>빌드 실행</li></ol><p>이렇게 <code>steps</code> 아래에 여러개의 명령을 설정할 수 있습니다.</p><h2 id="워크플로우-만들기" tabindex="-1"><a class="header-anchor" href="#워크플로우-만들기" aria-hidden="true">#</a> 워크플로우 만들기</h2><p>레포지토리 안에서 <code>.github/workflows</code> 디렉토리를 만들어서 작업을 생성할 수 있습니다.<br> 서버는 Django-EC2.yml, 프론트는 vue-S3.yml로 파일을 만들어서 배포를 담당해줬습니다.</p><figure><img src="https://github.com/Zamoca42/vue-django-blog/assets/96982072/2932c13c-9d50-4bac-be93-12cbf1e59b35" alt="서버와 프론트 배포 워크플로우 파일을 만들기" tabindex="0" loading="lazy"><figcaption>서버와 프론트 배포 워크플로우 파일을 만들기</figcaption></figure><p>설정파일을 만들고 레포지토리에 push해주면 리포지토리의 Acitons탭에서 확인할 수 있습니다.</p><figure><img src="https://github.com/Zamoca42/vue-django-blog/assets/96982072/a0fa6037-e966-4af0-a6a4-e7802958a577" alt="vue-django-blog의 Actions탭 확인" tabindex="0" loading="lazy"><figcaption>vue-django-blog의 Actions탭 확인</figcaption></figure><h2 id="secret-등록" tabindex="-1"><a class="header-anchor" href="#secret-등록" aria-hidden="true">#</a> Secret 등록</h2><p>워크플로우를 실행하는 과정에서 AWS의 EC2나 S3에 접근해서 배포하려면 AWS의 계정에서 발급한 액세스 키와 비밀 키가 필요합니다. 액세스 키는 AWS에 접근할 수 있는 권한이기 때문에 직접 키를 노출하면 보안 이슈가 발생할 수 있습니다.<br> 리포지토리의 설정에 Secret을 이용해 액세스 키를 저장하면 키와 비밀키를 노출하지 않고<br> 워크플로우에서 사용할 수 있습니다.</p><figure><img src="https://github.com/Zamoca42/vue-django-blog/assets/96982072/52f8a752-7904-465f-8961-0626e14f99e8" alt="Actions를 사용할 리포지토리에서 Secrets 환경변수 등록" tabindex="0" loading="lazy"><figcaption>Actions를 사용할 리포지토리에서 Secrets 환경변수 등록</figcaption></figure>`,16),h={href:"https://docs.aws.amazon.com/ko_kr/singlesignon/latest/userguide/what-is.html",target:"_blank",rel:"noopener noreferrer"},m=t('<p>AWS에서 키 발급하고 screts에 등록하기까지 다음과 같은 과정이 필요합니다.</p><h3 id="aws-iam" tabindex="-1"><a class="header-anchor" href="#aws-iam" aria-hidden="true">#</a> AWS IAM</h3><figure><img src="https://github.com/Zamoca42/blog/assets/96982072/ea717df0-4361-4ef3-90e9-8d22e770fa70" alt="AWS IAM 화면" tabindex="0" loading="lazy"><figcaption>AWS IAM 화면</figcaption></figure><p>AWS IAM에 들어가서 사용자 생성을 누릅니다.</p><figure><img src="https://github.com/Zamoca42/blog/assets/96982072/7e83067c-6732-47be-b95e-9b5c586f6da0" alt="세부 정보 지정" tabindex="0" loading="lazy"><figcaption>세부 정보 지정</figcaption></figure><p>권한 이름에 적당한 이름을 적고 다음을 눌러 권한 정책을 설정하는 화면으로 넘어갑니다.</p><h3 id="권한-정책에-github-actions에-사용할-권한-추가" tabindex="-1"><a class="header-anchor" href="#권한-정책에-github-actions에-사용할-권한-추가" aria-hidden="true">#</a> 권한 정책에 Github Actions에 사용할 권한 추가</h3><figure><img src="https://github.com/Zamoca42/blog/assets/96982072/b10b6bff-d7e6-4260-8dda-882ece558eaa" alt="여기서 필요한 보안 정책을 지정할 수 있습니다." tabindex="0" loading="lazy"><figcaption>여기서 필요한 보안 정책을 지정할 수 있습니다.</figcaption></figure><p>AWS 배포에 필요한 보안 권한을 지정합니다. 우선 S3만 지정해보겠습니다.</p><figure><img src="https://github.com/Zamoca42/blog/assets/96982072/0ca596b4-0a6a-40ec-bce0-a89440e6697e" alt="S3 모든 접근 권한 정책을 설정" tabindex="0" loading="lazy"><figcaption>S3 모든 접근 권한 정책을 설정</figcaption></figure><p><code>AmazonS3FullAccess</code>를 설정하면 S3에 대한 모든 권한을 사용할 수 있습니다.<br> 만약에 EC2에 배포하려면 <code>AmazonEC2FullAccess</code>와 같은 권한이 필요합니다.</p><figure><img src="https://github.com/Zamoca42/blog/assets/96982072/1c36ec63-ee17-4282-a9c4-0b79dd1302b2" alt="이제 액세스키를 발급받으면 끝" tabindex="0" loading="lazy"><figcaption>이제 액세스키를 발급받으면 끝</figcaption></figure><p>액세스 키 만들기를 눌러서 나오는 액세스 키와 액세스 비밀 키를 리포지토리의 Secrets에 등록해줍니다.</p><figure><img src="https://github.com/Zamoca42/blog/assets/96982072/013e9fc2-7607-42fa-8c7b-783b08f321ff" alt="액세스 키는 AWS_ACCESS_KEY_ID, 비밀 키는 AWS_SECRET_ACCESS_KEY로 등록" tabindex="0" loading="lazy"><figcaption>액세스 키는 AWS_ACCESS_KEY_ID, 비밀 키는 AWS_SECRET_ACCESS_KEY로 등록</figcaption></figure><h3 id="키와-액세스-키를-github-레포지토리-리포지토리-actions에-등록" tabindex="-1"><a class="header-anchor" href="#키와-액세스-키를-github-레포지토리-리포지토리-actions에-등록" aria-hidden="true">#</a> 키와 액세스 키를 Github 레포지토리 리포지토리 Actions에 등록</h3><figure><img src="https://github.com/Zamoca42/blog/assets/96982072/c4e70695-9fa6-4603-831e-9c741bd35b20" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>액세스키와 비밀키, 지역까지 등록하면 AWS에 배포할 준비는 끝납니다.</p>',17);function k(f,v){const s=o("ExternalLinkIcon");return c(),l("div",null,[n("blockquote",null,[n("p",null,[n("a",u,[a("https://docs.github.com/ko/actions"),e(s)]),a(" - GitHub Actions 공식 문서")])]),r,n("p",null,[a("가상머신은"),d,n("a",b,[a("GitHub Actions에서 지원하는 가상머신"),e(s)]),a("을 사용할 수 있습니다.")]),g,n("p",null,[a("키를 발급받는 방법은 "),n("a",h,[a("AWS 문서"),e(s)]),a("에 자세히 나와있습니다.")]),m])}const y=i(p,[["render",k],["__file","github-actions.html.vue"]]);export{y as default};
